simple_types.code:
type Declaration_Kind is
  (spec_unresolved, spec_resolved, complete,
   param_in, param_in_out, param_out);

record_types.code:
type Array_Table_Entry is record
  Index_xTyp   : Exact_Subtyp;
  Element_Size : Index;
  Element_xTyp : Exact_Subtyp;
  Array_Size   : Index;
  dimensions   : Positive;
end record;

type Block_Table_Entry is record
  Id                 : Alfa;
  Last_Id_Idx        : Index;
  First_Param_Id_Idx : Index;
  Last_Param_Id_Idx  : Index;
  PSize              : Index;
  VSize              : Index := 0;
  SrcFrom            : Positive;
  SrcTo              : Positive;
end record;

type Compilation_Trace_Parameters is record
  pipe         : Defs.Smart_Error_Pipe := null;
  progress     : Compilation_Feedback  := null;
  detail_level : Natural               := 0;
end record;

type Constant_Rec is record
  TP : Exact_Subtyp;
  I  : HAC_Integer;
  R  : HAC_Float;
end record;

type Current_Unit_Data is record
  compiler_stream   : Source_Stream_Access;
  source_file_name  : HAT.VString;
  buffer            : Source_Buffer_String;
  buffer_length     : Natural;
  buffer_position   : Positive;
  location          : Symbol_Location;
  input_line        : Source_Line_String;
  c, prev_c         : Character;
  CC                : Integer;
  LL                : Natural;
  level_0_def       : Id_Maps.Map;
  Use_HAT_Stack     : Use_HAT_Stack_Type;
  use_hat_stack_top : Natural;
end record;

type Identifier_Table_Entry is record
  name             : Alfa;
  name_with_case   : Alfa;
  link             : Index;
  entity           : Entity_Kind;
  decl_kind        : Declaration_Kind;
  xtyp                  : Exact_Subtyp;
  block_or_pkg_ref      : Index;
  normal                : Boolean;
  lev                   : Nesting_Level;
  adr_or_sz             : HAC_Integer;
  is_referenced         : Boolean;
  is_read               : No_Maybe_Yes;
  is_written_after_init : No_Maybe_Yes;
  is_initialized        : Initialized_Kind;
  location              : Symbol_Location;
end record;

