record_types.code:
type Loop_Info is record
  loop_Id     : Natural;
  is_FOR_loop : Boolean;
  start_line  : Natural;
end record;

type Package_Table_Entry is record
  first_public_declaration  : Positive;
  last_public_declaration   : Natural;
  last_private_declaration  : Natural;
